1	\chapter{Sheaves of $k$-modules: sheafification, Ext, and the structure sheaf as a sheaf of $k$-modules}
2	\label{chap:Cohomology_StructureSheafModuleK}
3	
4	This chapter implements Phase~A step~5 of \texttt{STRATEGY.md}: equipping $H^1(C, \struct C)$ with a $k$-vector-space structure when $C$ is a scheme over $\Spec k$. The route is through Mathlib's general $\Linear k$ enrichment of $\Sheaf(\opens X, \ModuleCat k)$ together with \lstinline{CategoryTheory.Abelian.Ext.instModule}, which automatically provides $\Module k$ on $\Ext$ groups in any $\Linear k$ abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of $H^1(C, \struct C)$ in Definition~\ref{def:genus}.
5	
6	The chapter is split into two sections of work. Section~\ref{sec:moduleK_prereqs} and~\ref{sec:moduleK_ext} (the iteration~005 work) provide the typeclass plumbing — the $\HasSheafify$ and $\HasExt$ instances on $\Sheaf(\opens X, \ModuleCat k)$. Section~\ref{sec:scheme_toModuleKSheaf} (the iteration~006 work) provides the \emph{substantive} content of Phase~A step~5: the $\ModuleCat k$-valued structure sheaf $\toModuleKSheaf C$ for $C : \mathrm{Over}\,(\Spec k)$, viewing $\struct C$ as a sheaf of $k$-modules via the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of $\genus C$ as $\dim_k H^1(C, \struct C)$ is then Phase~A step~6 (Serre finiteness, multi-iteration).
7	
8	A discovery probe of Mathlib \texttt{b80f227} (logged in \texttt{task\_pending.md}) confirms that the four typeclass pieces of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} are already in Mathlib (no new mathematical content; only universe-pinned packaging) and that the eight pieces of Section~\ref{sec:scheme_toModuleKSheaf} type-check end-to-end (~80 LOC; one short proof per piece). After this chapter lands, the typeclass chain \[ \HasSheafify \to \HasExt \to \Linear k \to \mathtt{Ext.instModule} \] is in place and $\toModuleKSheaf C$ provides the actual carrier on which it operates; the $\Module k$ instance on $H^1(C, \struct C) := (\toModuleKSheaf C).\mathtt H\,1$ is then automatic.
9	
10	\section{Sheafification of $\ModuleCat k$-valued sheaves on opens}
11	\label{sec:moduleK_prereqs}
12	
13	\begin{theorem}[Sheafification on the topology of opens, $\ModuleCat k$-valued]
14	  \label{thm:HasSheafify_Opens_ModuleCatK}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
16	  \leanok
17	  Let $k$ be a commutative ring and $X$ a topological space. Then the Grothendieck topology of opens of $X$ has
18	  \[
19	    \mathtt{HasSheafify}(\opens(X), \ModuleCat\, k).
20	  \]
21	\end{theorem}
22	
23	\begin{proof}
24	  \leanok
25	  Mathlib's general sheafification API constructs \lstinline{HasSheafify J A} whenever \lstinline{HasWeakSheafify J A} holds and the resulting sheafification preserves finite limits. For \lstinline{J = Opens.grothendieckTopology X} and \lstinline{A = ModuleCat k} both prerequisites are wired in Mathlib (small-site sheafification on a concrete category, plus exactness of $\ModuleCat k$-valued sheafification). The instance is therefore inferable; the prover's task is to reproduce the universe pinning that succeeded for the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasSheafify_Opens_AddCommGrp}).
26	\end{proof}
27	
28	\section{$\Ext$ for $\ModuleCat k$-valued sheaves on opens}
29	\label{sec:moduleK_ext}
30	
31	\begin{theorem}[$\Ext$ on the topology of opens, $\ModuleCat k$-valued]
32	  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
33	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
34	  \uses{thm:HasSheafify_Opens_ModuleCatK}
35	  \leanok
36	  Let $k$ be a commutative ring and $X$ a topological space. Then the category $\Sheaf(\opens(X), \ModuleCat k)$ has
37	  \[
38	    \mathtt{HasExt.\{u+1\}}\bigl(\Sheaf(\opens(X), \ModuleCat k)\bigr).
39	  \]
40	\end{theorem}
41	
42	\begin{proof}
43	  \uses{thm:HasSheafify_Opens_ModuleCatK}
44	  \leanok
45	  $\ModuleCat k$ is abelian. The sheaf category $\Sheaf(J, A)$ inherits an abelian structure from an abelian $A$ once \lstinline{HasSheafify J A} holds (Theorem~\ref{thm:HasSheafify_Opens_ModuleCatK}). Mathlib's \lstinline{CategoryTheory.HasExt.standard} produces a \lstinline{HasExt} instance from any abelian category. The universe annotation \lstinline{HasExt.\{u+1\}} matches the unique morphism universe of \lstinline{Sheaf (Opens.gT X) (ModuleCat.\{u\} k)}, mirroring the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasExt_Sheaf_Opens_AddCommGrp}).
46	\end{proof}
47	
48	\section{The structure sheaf of a $\Spec k$-scheme as a sheaf of $k$-modules}
49	\label{sec:scheme_toModuleKSheaf}
50	
51	This section provides the substantive content of Phase~A step~5: for $C : \Over\,(\Spec\,(\CommRingCat\,k))$, equipping the structure sheaf $\struct C$ with a sheaf-of-$k$-modules structure via the algebra map induced by the structure morphism $C.\mathrm{hom} : C.\mathrm{left} \to \Spec\,(\CommRingCat\,k)$. Together with the typeclass plumbing of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} and Mathlib's \lstinline{CategoryTheory.Abelian.Ext.instModule}, this completes the typeclass chain that gives $H^1(C, \struct C)$ a $\Module k$ structure.
52	
53	\subsection{The algebra map from the structure morphism}
54	
55	For each open $U \subseteq C.\mathrm{left}$, the structure morphism induces a chain of ring maps
56	\[
57	  k \xrightarrow{(\Gamma\!\Spec\!\mathrm{Iso}\,k)^{-1}} \Gamma(\Spec\,k, \top) \xrightarrow{C.\mathrm{hom}.\mathrm{app}\,\top} \Gamma(C.\mathrm{left}, C.\mathrm{hom}^{-1}\top) \xrightarrow{\rho} \Gamma(C.\mathrm{left}, U),
58	\]
59	where $\rho$ is the restriction along $U \le C.\mathrm{hom}^{-1}\top = \top$. Mathlib's \lstinline{Scheme.\Gamma SpecIso} provides the first iso, and the rest is the ordinary \lstinline{Scheme.Hom.app} together with the action of the presheaf on the inclusion $U \le \top$.
60	
61	\begin{definition}[Algebra map on a section]
62	  \label{def:Scheme_kToSection}
63	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection}
64	  \uses{def:Scheme_toAbSheaf}
65	  \leanok
66	  Let $k$ be a commutative ring and $C : \Over\,(\Spec\,(\CommRingCat\,k))$. For any open $U$ of $C.\mathrm{left}$, define
67	  \[
68	    \mathtt{kToSection}\,C\,U \;\colon\; \CommRingCat\,k \;\longrightarrow\; \Gamma(C.\mathrm{left}, U)
69	  \]
70	  to be the composition $(\Gamma\!\Spec\!\mathrm{Iso}\,(\CommRingCat\,k))^{-1} \circ (C.\mathrm{hom}.\mathrm{app}\,\top) \circ \rho$, where $\rho$ is the restriction map of $C.\mathrm{left}$ from $\top$ to $U$.
71	\end{definition}
72	
73	\begin{definition}[Algebra structure on a section]
74	  \label{def:Scheme_algebraSection}
75	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraSection}
76	  \uses{def:Scheme_kToSection}
77	  \leanok
78	  The ring map $\mathtt{kToSection}\,C\,U$ exhibits $\Gamma(C.\mathrm{left}, U)$ as a $k$-algebra. We register the resulting $\Algebra\,k\,(\Gamma(C.\mathrm{left}, U))$ instance via \lstinline{RingHom.toAlgebra}.
79	\end{definition}
80	
81	\begin{lemma}[Defining identity for the algebra map]
82	  \label{lem:Scheme_algebraMap_eq_kToSection}
83	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_eq_kToSection}
84	  \uses{def:Scheme_algebraSection}
85	  \leanok
86	  Under the algebra structure of Definition~\ref{def:Scheme_algebraSection},
87	  \[
88	    \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U)) \;=\; (\mathtt{kToSection}\,C\,U).\mathrm{hom}.
89	  \]
90	\end{lemma}
91	
92	\begin{proof}
93	  \uses{def:Scheme_algebraSection}
94	  \leanok
95	  Definitionally true: \lstinline{RingHom.toAlgebra}$\,(f).\mathrm{algebraMap} = f$.
96	\end{proof}
97	
98	\subsection{Naturality of the algebra map}
99	
100	\begin{lemma}[Restriction is compatible with the algebra map]
101	  \label{lem:Scheme_kToSection_naturality}
102	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.kToSection_naturality}
103	  \uses{def:Scheme_kToSection}
104	  \leanok
105	  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ (i.e.\ $V \le U$ in $\opens(C.\mathrm{left})$),
106	  \[
107	    \mathtt{kToSection}\,C\,U \,\circ\, C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f \;=\; \mathtt{kToSection}\,C\,V.
108	  \]
109	\end{lemma}
110	
111	\begin{proof}
112	  \uses{def:Scheme_kToSection}
113	  \leanok
114	  Both sides factor through $C.\mathrm{hom}.\mathrm{app}\,\top : \Gamma(\Spec k, \top) \to \Gamma(C.\mathrm{left}, \top)$. The remaining triangle on $\opens(C.\mathrm{left})$ commutes by functoriality of $C.\mathrm{left}.\mathtt{presheaf}$ on the composable inclusions $V \le U \le \top$.
115	\end{proof}
116	
117	\begin{lemma}[Algebra-map naturality]
118	  \label{lem:Scheme_algebraMap_naturality}
119	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf.algebraMap_naturality}
120	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
121	  \leanok
122	  For any $f : U \to V$ in $\opens(C.\mathrm{left})^{\mathrm{op}}$ and $r \in k$,
123	  \[
124	    (C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f).\mathrm{hom}\bigl(\mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, U))\,r\bigr) \;=\; \mathtt{algebraMap}\,k\,(\Gamma(C.\mathrm{left}, V))\,r.
125	  \]
126	\end{lemma}
127	
128	\begin{proof}
129	  \uses{lem:Scheme_kToSection_naturality, lem:Scheme_algebraMap_eq_kToSection}
130	  \leanok
131	  Lemma~\ref{lem:Scheme_algebraMap_eq_kToSection} reduces both sides to the underlying ring map of $\mathtt{kToSection}$; Lemma~\ref{lem:Scheme_kToSection_naturality} then closes the goal by congruence.
132	\end{proof}
133	
134	\subsection{The presheaf of $k$-modules and its sheaf condition}
135	
136	\begin{definition}[Presheaf of $k$-modules from $\struct C$]
137	  \label{def:Scheme_toModuleKPresheaf}
138	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf}
139	  \uses{def:Scheme_algebraSection, lem:Scheme_algebraMap_naturality}
140	  \leanok
141	  Define the presheaf
142	  \[
143	    \mathtt{toModuleKPresheaf}\,C \;\colon\; \opens(C.\mathrm{left})^{\mathrm{op}} \;\longrightarrow\; \ModuleCat\,k
144	  \]
145	  by
146	  \[
147	    \mathtt{toModuleKPresheaf}\,C \,.\,\mathrm{obj}\,U \;:=\; \ModuleCat.\mathrm{of}\,k\,(\Gamma(C.\mathrm{left}, U)),
148	  \]
149	  with the action of $k$ given by the algebra structure of Definition~\ref{def:Scheme_algebraSection}, and on a morphism $f : U \to V$ by the restriction map $(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}\,f).\mathrm{hom}$, viewed as a $k$-linear map. The action on morphisms is well-defined because the underlying ring map preserves $+$ and is $k$-linear by the naturality lemma~\ref{lem:Scheme_algebraMap_naturality}: $\rho(\mathtt{algebraMap}\,r \cdot x) = \rho(\mathtt{algebraMap}\,r) \cdot \rho(x) = \mathtt{algebraMap}\,r \cdot \rho(x)$. Functoriality reduces to $C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map\_id}$ and \lstinline{map_comp}.
150	\end{definition}
151	
152	\begin{theorem}[Sheaf condition]
153	  \label{thm:Scheme_toModuleKPresheaf_isSheaf}
154	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_isSheaf}
155	  \uses{def:Scheme_toModuleKPresheaf, thm:HasSheafify_Opens_ModuleCatK}
156	  \leanok
157	  $\mathtt{toModuleKPresheaf}\,C$ is a sheaf for the Grothendieck topology $\Opens.\mathrm{grothendieckTopology}\,C.\mathrm{left}.\mathrm{toTopCat}$.
158	\end{theorem}
159	
160	\begin{proof}
161	  \uses{def:Scheme_toModuleKPresheaf}
162	  \leanok
163	  By the concrete-category criterion \lstinline{Presheaf.isSheaf_iff_isSheaf_forget} applied to the forgetful functor $\ModuleCat\,k \to \Type$, it suffices to show that $\mathtt{toModuleKPresheaf}\,C \,\circ\, \mathrm{forget}\,(\ModuleCat\,k)$ is a sheaf in $\Type$. By construction, this composite agrees on objects and morphisms with $C.\mathrm{left}.\mathtt{presheaf} \,\circ\, \mathrm{forget}\,\CommRingCat$. The latter is a sheaf in $\Type$ because $C.\mathrm{left}.\mathtt{sheaf}$ is a sheaf in $\CommRingCat$ and \lstinline{Presheaf.isSheaf_iff_isSheaf_forget} also applies on the $\CommRingCat$ side.
164	\end{proof}
165	
166	\subsection{The structure sheaf as a sheaf of $k$-modules}
167	
168	\begin{definition}[Structure sheaf as a sheaf of $k$-modules]
169	  \label{def:Scheme_toModuleKSheaf}
170	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf}
171	  \uses{def:Scheme_toModuleKPresheaf, thm:Scheme_toModuleKPresheaf_isSheaf}
172	  \leanok
173	  Bundle Definition~\ref{def:Scheme_toModuleKPresheaf} and Theorem~\ref{thm:Scheme_toModuleKPresheaf_isSheaf} into the sheaf
174	  \[
175	    \mathtt{toModuleKSheaf}\,C \;\colon\; \Sheaf\bigl(\opens(C.\mathrm{left}.\mathrm{toTopCat}),\ \ModuleCat\,k\bigr).
176	  \]
177	\end{definition}
178	
179	\subsection{Forget-and-recover: bridging $\toModuleKSheaf$ and $\toAbSheaf$}
180	
181	The iter-007 polish track adds two consumer-facing helpers. The first records that, after forgetting from $\ModuleCat\,k$ to $\AddCommGrpCat$ via $\forget_2$, the iter-006 sheaf agrees on the nose with the iter-004 abelian-group-level structure sheaf $\toAbSheaf\,C.\mathrm{left}$. This is what allows downstream consumers (cohomology comparisons, derived-functor identifications) to transport between the two flavours.
182	
183	\begin{definition}[Forget-and-recover natural iso for $\toModuleKSheaf$]
184	  \label{def:Scheme_toModuleKSheaf_forgetCompare}
185	  \lean{AlgebraicGeometry.Scheme.toModuleKSheaf_forgetCompare}
186	  \uses{def:Scheme_toModuleKSheaf, def:Scheme_toAbSheaf}
187	  \leanok
188	  Let $C : \Over\,(\Spec\,(\CommRingCat\,k))$. Then there is an isomorphism of sheaves of abelian groups
189	  \[
190	    (\sheafCompose\,(\opens.\mathrm{grothendieckTopology}\,C.\mathrm{left}.\mathrm{toTopCat})\,(\forget_2\,(\ModuleCat\,k)\,\AddCommGrpCat)).\mathrm{obj}\,(\toModuleKSheaf\,C) \;\cong\; \toAbSheaf\,C.\mathrm{left}.
191	  \]
192	\end{definition}
193	
194	\begin{proof}
195	  \uses{def:Scheme_toModuleKSheaf, def:Scheme_toAbSheaf}
196	  \leanok
197	  Definitionally true: both sides have $(\AddCommGrpCat.\mathrm{of}\,(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{obj}\,U))$ at every $U$ (via the $\forget_2 (\ModuleCat\,k)\,\AddCommGrpCat$ on the LHS and the iter-004 $(\sheafCompose\,J\,(\forget_2\,\CommRingCat\,\RingCat\,\circ\,\forget_2\,\RingCat\,\AddCommGrpCat)).\mathrm{obj}\,C.\mathrm{left}.\mathrm{sheaf}$ unfolding on the RHS), and the action on morphisms is the underlying $C.\mathrm{left}.\mathtt{presheaf}.\mathrm{map}$ on both sides. The closure is \lstinline{Iso.refl _}; probe-confirmed (iteration~007 plan-agent \lstinline{lean_run_code}).
198	\end{proof}
199	
200	\begin{lemma}[Object-evaluation simp lemma for $\toModuleKPresheaf$]
201	  \label{lem:Scheme_toModuleKPresheaf_obj}
202	  \lean{AlgebraicGeometry.Scheme.toModuleKPresheaf_obj}
203	  \uses{def:Scheme_toModuleKPresheaf}
204	  \leanok
205	  For every $U \in \opens(C.\mathrm{left}.\mathrm{toTopCat})^{\mathrm{op}}$,
206	  \[
207	    (\toModuleKPresheaf\,C).\mathrm{obj}\,U \;=\; \ModuleCat.\mathrm{of}\,k\,(C.\mathrm{left}.\mathtt{presheaf}.\mathrm{obj}\,U).
208	  \]
209	\end{lemma}
210	
211	\begin{proof}
212	  \uses{def:Scheme_toModuleKPresheaf}
213	  \leanok
214	  Definitionally true by the construction of $\toModuleKPresheaf$ (Definition~\ref{def:Scheme_toModuleKPresheaf}). The closure is \lstinline{rfl}; the lemma is tagged \lstinline{@[simp]} so consumers can rewrite without unfolding the constructor.
215	\end{proof}
216	
217	\section{Sheaf cohomology with $\ModuleCat k$ coefficients}
218	\label{sec:HModule}
219	
220	Mathlib provides $\Sheaf.\mathtt{H} \,\colon\, \Sheaf\,J\,\AddCommGrpCat \to \mathbb N \to \mathrm{Type}\,\_$ — an abstract Grothendieck-topology cohomology in $\AddCommGrpCat$. The value category is fixed to $\AddCommGrpCat$; there is no $\ModuleCat k$-flavoured analogue in Mathlib. The iter-009 finding (logged in \texttt{task\_pending.md}) is that closing $\genus C$ honestly as $\dim_k H^1(C, \struct C)$ requires a parallel sheaf cohomology valued in $\ModuleCat k$ rather than $\AddCommGrpCat$, since $\Module.\mathtt{finrank}\,k$ requires a $\Module k$ structure that the $\AddCommGrpCat$-valued $\Sheaf.\mathtt H$ cannot provide.
221	
222	The construction is short. The $\Linear k$-enriched abelian category $\Sheaf(J, \ModuleCat k)$ already has $\HasExt$ (Theorem~\ref{thm:HasExt_Sheaf_Opens_ModuleCatK}), and $\Ext$ groups in any $\Linear k$ abelian category carry a canonical $\Module k$ structure via \lstinline{CategoryTheory.Abelian.Ext.instModule}. We mirror $\Sheaf.\mathtt H$'s standard construction $\Ext(\mathtt{constantSheaf}.\mathrm{obj}\,1, F, n)$ with $\AddCommGrpCat$ replaced by $\ModuleCat k$ and the unit object $1$ replaced by $\ModuleCat.\mathrm{of}\,k\,k$.
223	
224	\begin{definition}[Sheaf cohomology with $\ModuleCat k$ coefficients]
225	  \label{def:Scheme_HModule}
226	  \lean{AlgebraicGeometry.Scheme.HModule}
227	  \leanok
228	  \uses{thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
229	  Let $k$ be a field, $C$ a category with $J : \mathrm{GrothendieckTopology}\,C$, and assume $\HasSheafify\,J\,(\ModuleCat\,k)$ and $\HasExt(\Sheaf(J, \ModuleCat\,k))$. For $F : \Sheaf(J, \ModuleCat\,k)$ and $n \in \mathbb N$, define the $\ModuleCat k$-flavoured sheaf cohomology
230	  \[
231	    \mathtt{HModule}\,k\,F\,n \;:=\; \Ext\bigl((\mathtt{constantSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k),\ F,\ n\bigr),
232	  \]
233	  where $\Ext$ is the standard \lstinline{CategoryTheory.Abelian.Ext} construction. This is automatically a $\Module k$-module via \lstinline{Abelian.Ext.instModule}.
234	\end{definition}
235	
236	\begin{remark}[Choice of \texttt{abbrev} over \texttt{def}]
237	  The Lean implementation uses \lstinline{noncomputable abbrev} rather than \lstinline{noncomputable def}. The reason is that instance synthesis must see through the wrapper to find the $\Module\,k$ and $\AddCommGroup$ instances on the underlying $\Ext$ group. A \lstinline{def} blocks unfolding, and the iter-009 plan-agent probe verified that \lstinline{Module k (HModule k F n)} fails to synthesize (\texttt{failed to synthesize instance of type class AddCommMonoid}) under \lstinline{def}. Switching to \lstinline{abbrev} makes the wrapper reducible, and instance synthesis succeeds for both $\Module\,k$ and $\AddCommGroup$. The \lstinline{noncomputable} modifier is required because \lstinline{Abelian.Ext.instModule} is itself noncomputable.
238	\end{remark}
239	
240	\begin{remark}[Universe parameters]
241	  The signature mirrors Mathlib's \lstinline{Sheaf.H} \[\{C : \mathrm{Type}\,u_4\}\,[\Category.\{u_3, u_4\}\,C]\,\{J : \mathrm{GrothendieckTopology}\,C\}\,(F : \Sheaf\,J\,\AddCommGrpCat) \dots\] using fully general universes $\{u, v\}$: the morphism universe of $C$ is pinned to $u$ to match $\ModuleCat.\{u\}\,k$, the object universe of $C$ is left as $v$. For the project's primary use case ($J = \opens.\mathrm{grothendieckTopology}\,X.\mathrm{toTopCat}$ with $X : \Scheme.\{u\}$), one has $v = u$ and $\Category.\{u, u\}$. The iter-009 plan-agent probe verified both the abstract general-$v$ case and the concrete $v = u$ specialisation.
242	\end{remark}
243	
244	\section{The $H^0$ algebraic bridge}
245	\label{sec:HModule_zero}
246	
247	After Definition~\ref{def:Scheme_HModule} the cohomology groups $\HModule\,k\,F\,n$ are well-defined and carry the canonical $\Module k$-structure inherited from \lstinline{Abelian.Ext.instModule}. For Phase~A step~6 (Serre finiteness, deferred), the next algebraic preliminary is the identification of the degree-zero piece $\HModule\,k\,F\,0$ with a Hom group: this is the bridge from sheaf cohomology to representable Hom-functors, and on a connected proper $k$-curve it eventually rewrites $H^0(C, \struct C)$ as $\Gamma(C, \struct C)$ viewed as a $k$-module.
248	
249	The Lean implementation reuses Mathlib's \lstinline{CategoryTheory.Abelian.Ext.linearEquiv₀} (file \lstinline{Mathlib/Algebra/Homology/DerivedCategory/Ext/Linear.lean}), which provides
250	\[
251	  \Ext_R(X, Y, 0) \;\simeq_R\; (X \to Y)
252	\]
253	in any $\Linear R$-enriched abelian category for $R$ a commutative ring. Specialised to $R = k$ and to the $\Linear k$-enriched abelian category $\Sheaf(J, \ModuleCat\,k)$ (the $\Linear k$ enrichment is auto-inferable from \lstinline{HasSheafify} via \lstinline{Sheaf.linear}; this typeclass-level inference is verified by an iter-010 plan-agent \lstinline{lean_run_code} probe), the equivalence specialises to
254	\[
255	  \HModule\,k\,F\,0 \;\simeq_k\; \bigl((\mathtt{constantSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \,\to\, F\bigr).
256	\]
257	
258	\begin{definition}[$H^0$ as a $k$-linear Hom group]
259	  \label{def:Scheme_HModule_zero_linearEquiv}
260	  \lean{AlgebraicGeometry.Scheme.HModule_zero_linearEquiv}
261	  \leanok
262	  \uses{def:Scheme_HModule, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
263	  Let $k$ be a field, $C$ a category with $J : \mathrm{GrothendieckTopology}\,C$, and assume $\HasSheafify\,J\,(\ModuleCat\,k)$ and $\HasExt(\Sheaf(J, \ModuleCat\,k))$. For $F : \Sheaf(J, \ModuleCat\,k)$, the $k$-linear equivalence
264	  \[
265	    \mathtt{HModule\_zero\_linearEquiv}_F \,:\, \HModule\,k\,F\,0 \;\simeq_k\; \bigl((\mathtt{constantSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to F\bigr)
266	  \]
267	  is given by \lstinline{Abelian.Ext.linearEquiv₀}.
268	\end{definition}
269	
270	\begin{proof}
271	  \leanok
272	  \uses{def:Scheme_HModule}
273	  Direct from \lstinline{CategoryTheory.Abelian.Ext.linearEquiv₀} applied to the abelian category $\Sheaf(J, \ModuleCat\,k)$, which is $\Linear k$-enriched (auto-inferable from the prerequisites of Section~\ref{sec:moduleK_prereqs}) and has $\HasExt$ (Theorem~\ref{thm:HasExt_Sheaf_Opens_ModuleCatK}). The $\noncomputable$ \lstinline{abbrev} reducibility of $\HModule\,k\,F\,0$ (Definition~\ref{def:Scheme_HModule}) lets instance synthesis unfold the wrapper to the underlying $\Ext$ group, and \lstinline{linearEquiv₀} returns the $\Module k$-linear bijection between that $\Ext$ group and the corresponding Hom group in the sheaf category. The closure body is therefore a one-liner \lstinline{Abelian.Ext.linearEquiv₀}; iter-010 plan-agent \lstinline{lean_run_code} probe confirms the closure compiles end-to-end against current Mathlib.
274	\end{proof}
275	
276	\begin{remark}[Why \texttt{linearEquiv} and not \texttt{addEquiv} or \texttt{equiv}]
277	  Mathlib provides three flavours of the $\Ext^0 \simeq \Hom$ equivalence: \lstinline{Abelian.Ext.homEquiv₀} (plain $\simeq$), \lstinline{Abelian.Ext.addEquiv₀} (additive $\simeq^+$), \lstinline{Abelian.Ext.linearEquiv₀} ($R$-linear $\simeq_R$). The iter-010 implementation chooses the strongest, \lstinline{linearEquiv₀}, because the $k$-linear refinement is the one consumed downstream: $\Module.\mathtt{Finite}\,k\,(\HModule\,k\,F\,0) \iff \Module.\mathtt{Finite}\,k\,((\mathtt{constantSheaf}\dots) \to F)$ via \lstinline{Module.Finite.equiv}, which requires a $\Module k$-linear equivalence on its left side.
278	\end{remark}
279	
280	\begin{remark}[Why this bridge and not \texttt{HModule\_forget}]
281	  Session~15's \texttt{recommendations.md} proposed an alternative iter-010 polish lemma \lstinline{HModule_forget}: a simp lemma identifying the $\forget_2 (\ModuleCat\,k)\,\AddCommGrpCat$-image of $\HModule\,k\,F\,n$ with $\Sheaf.\mathtt H\,((\sheafCompose\,\_\,(\forget_2\,\dots)).\mathrm{obj}\,F)\,n$. Iter-010 plan-agent re-read of Mathlib's \lstinline{CategoryTheory/Sites/SheafCohomology/Basic.lean} reveals that $\Sheaf.\mathtt H\,F\,n := \Ext\bigl((\mathtt{constantSheaf}\,J\,\_).\mathrm{obj}\,(\AddCommGrpCat.\mathrm{of}\,(\ULift\,\mathbb Z)),\ F,\ n\bigr)$ — the unit object is $\ULift\,\mathbb Z$, whereas $\HModule$ uses $\ModuleCat.\mathrm{of}\,k\,k$. The two unit objects are unrelated under $\forget_2 (\ModuleCat\,k)\,\AddCommGrpCat$ (the former forgets to $\AddCommGrpCat.\mathrm{of}\,k$, not $\AddCommGrpCat.\mathrm{of}\,(\ULift\,\mathbb Z)$). The two cohomology theories are related by a change-of-coefficient comparison map, but it is generically not an isomorphism — so \lstinline{HModule_forget} as proposed is not a \lstinline{rfl}/single-application closure. Iter-010 instead targets this $H^0$ bridge, which is genuinely a one-liner and is the algebraic fact downstream consumers actually need.
282	\end{remark}
283	
284	\section{Čech cohomology of the structure sheaf (iter-012 scaffold)}
285	\label{sec:moduleK_cech}
286	
287	This section opens \emph{Path-2} of Phase~A step~6: the Čech-cohomology approach to Serre finiteness for $H^i(C, \struct C)$ on a smooth proper geometrically irreducible curve. Iter-012 lays the smallest useful sub-step: define the Čech complex of $\toModuleKSheaf C$ for an arbitrary indexed open cover, plus its cohomology object in each degree. Iter-013+ will add the comparison theorem (Čech vs derived-functor cohomology, for an acyclic cover), the affine-finiteness step (each cochain group is a finite-dimensional $k$-vector space when the cover is affine), and the dimension-vanishing step (degree $> 1$ vanishes on a curve); together they will produce the Serre-finiteness instance \lstinline{Module.Finite k (HModule k (toModuleKSheaf C) i)} that downstream \lstinline{smoothOfRelativeDimension_genus} consumes.
288	
289	The carrier on which the iter-013+ work will operate is the Mathlib functor \lstinline{CategoryTheory.cechComplexFunctor} (\texttt{Mathlib/CategoryTheory/Sites/SheafCohomology/Cech.lean}): given a presheaf $F : \Cop \to A$ on a category $C$ with finite products, valued in a preadditive category $A$ with products, and an indexed family $\mathcal U : \iota \to C$, this returns a cochain complex
290	\[
291	  \check C^\bullet(\mathcal U; F) \;:=\; (\mathtt{cechComplexFunctor}\,\mathcal U).\mathrm{obj}\,F \;\in\; \mathtt{CochainComplex}(A, \mathbb N).
292	\]
293	For $A = \ModuleCat\,k$, $C = \opens(C.\mathrm{left}.\mathtt{toTopCat})$ (a complete lattice, hence a category with finite products via meets), and $F = (\mathtt{sheafToPresheaf}\,\_\,\_).\mathrm{obj}\,(\toModuleKSheaf C)$ the underlying presheaf of the iter-006 structure sheaf, the Čech complex is well-defined; its $n$-th cohomology lives in $\ModuleCat\,k$.
294	
295	\begin{definition}[Čech complex of the structure sheaf]
296	  \label{def:Scheme_cechCochain_OC}
297	  \lean{AlgebraicGeometry.Scheme.cechCochain_OC}
298	  \leanok
299	  \uses{def:Scheme_toModuleKSheaf}
300	  Let $C : \Over\,(\Spec\,(\CommRingCat\,k))$ and $\mathcal U : \iota \to \opens C.\mathrm{left}.\mathtt{toTopCat}$ be an indexed family of opens. Define
301	  \[
302	    \mathtt{cechCochain\_OC}\,(C)(\mathcal U) \;:=\; (\mathtt{cechComplexFunctor}\,\mathcal U).\mathrm{obj}\,\bigl((\mathtt{sheafToPresheaf}\,\_\,\_).\mathrm{obj}\,(\toModuleKSheaf C)\bigr).
303	  \]
304	  This is a cochain complex valued in $\ModuleCat.\{u\}\,k$, indexed by $\mathbb N$.
305	\end{definition}
306	
307	\begin{proof}
308	  \leanok
309	  \uses{def:Scheme_toModuleKSheaf}
310	  Direct application of Mathlib's \lstinline{cechComplexFunctor}. The required typeclasses (\lstinline{HasProducts (ModuleCat.{u} k)}, \lstinline{HasFiniteProducts (Opens C.left.toTopCat)}, \lstinline{Preadditive (ModuleCat.{u} k)}) are all auto-resolved. The closure body is therefore the one-line term \lstinline{(cechComplexFunctor 𝒰).obj ((sheafToPresheaf _ _).obj (Scheme.toModuleKSheaf C))}; iter-012 plan-agent \lstinline{lean_run_code} probe confirms this typechecks end-to-end against current Mathlib + project state.
311	\end{proof}
312	
313	\begin{definition}[Čech cohomology of the structure sheaf]
314	  \label{def:Scheme_cechCohomology_OC}
315	  \lean{AlgebraicGeometry.Scheme.cechCohomology_OC}
316	  \leanok
317	  \uses{def:Scheme_cechCochain_OC}
318	  With $(C, \mathcal U)$ as in Definition~\ref{def:Scheme_cechCochain_OC}, define for each $n : \mathbb N$
319	  \[
320	    \mathtt{cechCohomology\_OC}\,(C)(\mathcal U)(n) \;:=\; \bigl(\mathtt{cechCochain\_OC}\,(C)(\mathcal U)\bigr).\mathtt{homology}\,n \;\in\; \ModuleCat.\{u\}\,k.
321	  \]
322	\end{definition}
323	
324	\begin{proof}
325	  \leanok
326	  \uses{def:Scheme_cechCochain_OC}
327	  Direct application of \lstinline{HomologicalComplex.homology} on the cochain complex of Definition~\ref{def:Scheme_cechCochain_OC}. The closure body is the one-line term \lstinline{(Scheme.cechCochain_OC C 𝒰).homology n}.
328	\end{proof}
329	
330	\begin{remark}[What iter-012 does and does not do]
331	  Iter-012 \emph{defines} the Čech cochain complex and Čech cohomology object of the structure sheaf for an arbitrary indexed open cover. Iter-012 does \emph{not} prove that this Čech cohomology agrees with the derived-functor cohomology $\HModule\,k\,(\toModuleKSheaf C)\,n$ of Definition~\ref{def:Scheme_HModule} — the comparison theorem requires the cover to be \emph{acyclic} (e.g., all opens affine, plus Serre's vanishing on affine schemes for quasi-coherent sheaves), neither of which is iter-012 work. The comparison theorem is queued for iter-013+; the affine-finiteness step (each cochain group is finite-dimensional over $k$ when the cover is affine and the curve is proper) is queued for iter-014+; the dimension-vanishing step (degree $> 1$ vanishes on a curve) is queued for iter-015+.
332	\end{remark}
333	
334	\begin{remark}[Why two declarations and not one]
335	  Splitting $\check C^\bullet$ from $\check H^n$ matches Mathlib's standard pattern (\lstinline{cechComplexFunctor} returns a complex; \lstinline{HomologicalComplex.homology} extracts a degree). The complex is useful in its own right (e.g., for explicit cocycle / coboundary calculations, or for showing exactness on a specific cover), so we expose it as a separate API surface.
336	\end{remark}
