343	\begin{definition}[Cohomology of an open with \texorpdfstring{$\ModuleCat\,k$}{ModuleCat k} coefficients (iter-013)]
344	  \label{def:Scheme_HModule_prime}
345	  \lean{AlgebraicGeometry.Scheme.HModule'}
346	  \leanok
347	  \uses{def:Scheme_HModule}
348	  Let $k$ be a field, $(C, J)$ a Grothendieck site with $C : \mathrm{Type}\,v$ and $\Category.\{u, v\}\,C$, and $F : \Sheaf\,J\,(\ModuleCat.\{u\}\,k)$ an abelian sheaf (with $J$ admitting weak sheafification of $\mathrm{Type}\,u$, a sheafification of $\ModuleCat.\{u\}\,k$, and a $\HasExt$ instance on $\Sheaf\,J\,(\ModuleCat.\{u\}\,k)$). For $n : \mathbb N$ and $X : C$:
349	  \[
350	    \HModulePrime\,k\,F\,n\,X \;:=\; \Ext^n\bigl((\mathtt{presheafToSheaf}\,J\,(\ModuleCat\,k)).\mathrm{obj}\,((\yoneda \circ \mathtt{free}_k).\mathrm{obj}\,X),\; F\bigr) \;\in\; \mathrm{Type}\,u,
