355	\begin{proof}
356	  \leanok
357	  \uses{def:Scheme_HModule, thm:HasSheafify_Opens_ModuleCatK, thm:HasExt_Sheaf_Opens_ModuleCatK}
358	  Direct mirror of Mathlib's \lstinline{Sheaf.H'} (file \texttt{Mathlib/CategoryTheory/Sites/SheafCohomology/Basic.lean}). The body is the one-line term
359	  \[
360	    \mathtt{Abelian.Ext}\,((\mathtt{presheafToSheaf}\,\_\,\_).\mathrm{obj}\,((\yoneda \circ (\Functor.\whiskeringRight\,\_\,\_\,\_).\mathrm{obj}\,(\ModuleCat.\mathtt{free}\,k)).\mathrm{obj}\,X))\,F\,n.
